      out.write("        var filteredEmployees = [];\n");
      out.write("\n");
      out.write("        // Dynamic Formatter helper\n");
      out.write("        function formatDate(dateString) {\n");
      out.write("            if (!dateString || dateString === \"-\") return \"\";\n");
      out.write("            var months = [\"Jan\", \"Feb\", \"Mar\", \"Apr\", \"May\", \"Jun\", \"Jul\", \"Aug\", \"Sep\", \"Oct\", \"Nov\", \"Dec\"];\n");
      out.write("            var parts = dateString.split(\"-\");\n");
      out.write("            if (parts.length !== 3) return dateString;\n");
      out.write("            var year = parts[0];\n");
      out.write("            var month = months[parseInt(parts[1]) - 1];\n");
      out.write("            var day = parts[2];\n");
      out.write("            return day + \"-\" + month + \"-\" + year;\n");
      out.write("        }\n");
      out.write("\n");
      out.write("        // Initialize lists and choices on page load\n");
