      out.write("                'gender': 'filter-gender',\n");
      out.write("                'exDtMt': 'filter-exDtMt',\n");
      out.write("                'exServicemen': 'filter-exServicemen',\n");
      out.write("                'php': 'filter-php',\n");
      out.write("                'category': 'filter-category',\n");
      out.write("                'qualification': 'filter-qualification',\n");
      out.write("                'designation': 'filter-designation'\n");
      out.write("            };\n");
      out.write("            \n");
      out.write("            for (var key in categoricalCols) {\n");
      out.write("                var selectId = categoricalCols[key];\n");
      out.write("                var selectEl = document.getElementById(selectId);\n");
      out.write("                if (!selectEl) continue;\n");
      out.write("                \n");
      out.write("                var uniqueVals = {};\n");
      out.write("                allEmployees.forEach(function(emp) {\n");
      out.write("                    var val = emp[key];\n");
      out.write("                    if (val && val.trim() !== '') {\n");
      out.write("                        uniqueVals[val] = true;\n");
      out.write("                    }\n");
      out.write("                });\n");
      out.write("                \n");
      out.write("                var sortedVals = Object.keys(uniqueVals).sort();\n");
      out.write("                \n");
      out.write("                selectEl.innerHTML = '<option value=\"\">All</option>';\n");
      out.write("                sortedVals.forEach(function(val) {\n");
      out.write("                    var opt = document.createElement('option');\n");
      out.write("                    opt.value = val;\n");
      out.write("                    opt.innerText = val;\n");
      out.write("                    selectEl.appendChild(opt);\n");
      out.write("                });\n");
      out.write("            }\n");
      out.write("        }\n");
      out.write("\n");
      out.write("        // Top Filter synchronization\n");
