      out.write("\n");
      out.write("        // Filter calculation engine\n");
      out.write("        function applyFilters() {\n");
      out.write("            var textFilters = {\n");
      out.write("                'employeeId': document.getElementById('filter-employeeId').value.toLowerCase(),\n");
      out.write("                'employeeName': document.getElementById('filter-employeeName').value.toLowerCase(),\n");
      out.write("                'dob': document.getElementById('filter-dob').value.toLowerCase(),\n");
      out.write("                'retDate': document.getElementById('filter-retDate').value.toLowerCase(),\n");
      out.write("                'doj': document.getElementById('filter-doj').value.toLowerCase(),\n");
      out.write("                'doa': document.getElementById('filter-doa').value.toLowerCase(),\n");
      out.write("                'promoDate': document.getElementById('filter-promoDate').value.toLowerCase(),\n");
      out.write("                'remarks': document.getElementById('filter-remarks').value.toLowerCase()\n");
      out.write("            };\n");
      out.write("            \n");
      out.write("            var selectFilters = {\n");
      out.write("                'division': document.getElementById('filter-division').value,\n");
      out.write("                'complex': document.getElementById('filter-complex').value,\n");
      out.write("                'discipline': document.getElementById('filter-discipline').value,\n");
      out.write("                'grade': document.getElementById('filter-grade').value,\n");
      out.write("                'gender': document.getElementById('filter-gender').value,\n");
      out.write("                'exDtMt': document.getElementById('filter-exDtMt').value,\n");
      out.write("                'exServicemen': document.getElementById('filter-exServicemen').value,\n");
      out.write("                'php': document.getElementById('filter-php').value,\n");
      out.write("                'category': document.getElementById('filter-category').value,\n");
      out.write("                'qualification': document.getElementById('filter-qualification').value,\n");
      out.write("                'designation': document.getElementById('filter-designation').value\n");
      out.write("            };\n");
      out.write("\n");
      out.write("            filteredEmployees = allEmployees.filter(function(emp) {\n");
      out.write("                // Apply text filters\n");
      out.write("                for (var key in textFilters) {\n");
      out.write("                    var q = textFilters[key];\n");
      out.write("                    if (q !== '') {\n");
      out.write("                        var val = emp[key] ? emp[key].toLowerCase() : '';\n");
